    public static long[] solve(long[] nums, long[][] queries) {
        int n = nums.length;
        int m = queries.length;
        long[] result = new long[m];

        // Preprocess: For each index, store the frequency of elements in the subarray starting at that index
        // We use a list of maps to store the frequency counts for each starting index
        List<Map<Long, Integer>> freqMaps = new ArrayList<>();

        // Initialize the frequency maps
        for (int i = 0; i < n; i++) {
            Map<Long, Integer> map = new HashMap<>();
            map.put(nums[i], 1);
            freqMaps.add(map);
        }

        // Fill the frequency maps for subarrays starting at each index
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                Map<Long, Integer> map = new HashMap<>(freqMaps.get(i));
                map.put(nums[j], map.getOrDefault(nums[j], 0) + 1);
                freqMaps.set(i, map);
            }
        }

        // Process each query
        for (int i = 0; i < m; i++) {
            long li = queries[i][0];
            long ri = queries[i][1];
            long threshold = queries[i][2];

            Map<Long, Integer> freqMap = freqMaps.get((int) li);

            // Find the element that meets the threshold and has the highest frequency
            long ans = -1;
            int maxFreq = -1;

            for (Map.Entry<Long, Integer> entry : freqMap.entrySet()) {
                long num = entry.getKey();
                int freq = entry.getValue();

                if (freq >= threshold) {
                    if (freq > maxFreq || (freq == maxFreq && num < ans)) {
                        maxFreq = freq;
                        ans = num;
                    }
                }
            }

            result[i] = ans;
        }

        return result;
    }
