                int mid = (left + right) / 2;
                if (positions.get(mid) <= ri) left = mid + 1;
                else right = mid;
            }

            int end = left - 1;
            if (start <= end) {
                int count = end - start + 1;
                if (count >= (int) threshold) {
                    found = true;
                    // Update result if this element has higher frequency or same frequency but smaller value
